        data[offset + 3 * VERTICAL_STRIDE] = in[loader_x + y3 * sx];
        data[offset + 4 * VERTICAL_STRIDE] = in[loader_x + y4 * sx];
        data[offset + 2 * VERTICAL_STRIDE] = in[loader_x + y2 * sx];
        data[offset + 5 * VERTICAL_STRIDE] = in[loader_x + y5 * sx];
        data[offset + 1 * VERTICAL_STRIDE] = in[loader_x + y1 * sx];
        data[offset + 6 * VERTICAL_STRIDE] = in[loader_x + y6 * sx];
        data[offset + 0 * VERTICAL_STRIDE] = in[loader_x + y0 * sx];
    } else {
        for (int i = 0; i < 7; i++) {
            int y = loader_y + i;
            if (y >= sy) y = 2 * sy - 2 - y;
            if (y < 0) y = -y;
            data[offset + i * VERTICAL_STRIDE] = in[loader_x + y * sx];
        }
    }

    for (int w = 0; w < steps; w++) {
        for (int i = 7; i < (7 + WIN_SIZE_Y); i += 2) {
            int y = loader_y + i;
            if (y >= sy) y = 2 * sy - 2 - y;
            if (y < 0) y = -y;
            data[offset + i * VERTICAL_STRIDE] = in[loader_x + y * sx];
            int y_next = loader_y + i + 1;
            if (y_next >= sy) y_next = 2 * sy - 2 - y_next;
            if (y_next < 0) y_next = -y_next;
            data[offset + (i + 1) * VERTICAL_STRIDE] = in[loader_x + y_next * sx];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        for (int line = 7 + WIN_SIZE_Y - 1; line >= 7; line -= 2) {
            float p = data[offset + (line - 1) * VERTICAL_STRIDE];
            float n = data[offset + (line + 1) * VERTICAL_STRIDE];
            data[offset + line * VERTICAL_STRIDE] += r97update2 * (p + n);
        }
        for (int line = 7 + WIN_SIZE_Y - 2; line >= 7; line -= 2) {
            float p = data[offset + (line - 1) * VERTICAL_STRIDE];
            float n = data[offset + (line + 1) * VERTICAL_STRIDE];
            data[offset + line * VERTICAL_STRIDE] += r97predict2 * (p + n);
        }
        for (int line = 7 + WIN_SIZE_Y - 1; line >= 7; line -= 2) {
            float p = data[offset + (line - 1) * VERTICAL_STRIDE];
            float n = data[offset + (line + 1) * VERTICAL_STRIDE];
            data[offset + line * VERTICAL_STRIDE] += r97update1 * (p + n);
        }
        for (int line = 7 + WIN_SIZE_Y - 2; line >= 7; line -= 2) {
            float p = data[offset + (line - 1) * VERTICAL_STRIDE];
            float n = data[offset + (line + 1) * VERTICAL_STRIDE];
            data[offset + line * VERTICAL_STRIDE] += r97Predict1 * (p + n);
        }

        int outX = firstX_base + threadIdx_x;
        int outY_base = firstY + w * WIN_SIZE_Y * steps / steps;

        for (int i = 3; i < (3 + WIN_SIZE_Y); i++) {
            int y_out = outY_base + i;
            if (y_out < sy && outX < sx) {
                out[outX + y_out * sx] = data[offset + i * VERTICAL_STRIDE];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);
        loader_y += WIN_SIZE_Y;
    }
}
